package com.funkyotc.puzzleverse.sudoku.data

import com.funkyotc.puzzleverse.core.data.BrowseablePuzzle

data class PregeneratedSudoku(
    override val id: String,
    override val difficulty: String,
    val clues: Int,
    val puzzleStr: String,
    val solutionStr: String
) : BrowseablePuzzle {
    override val label: String get() = "Puzzle"
    override val subtitle: String get() = "$clues clues"
    val puzzle: List<List<Int>> get() = puzzleStr.map { it.digitToInt() }.chunked(9)
    val solution: List<List<Int>> get() = solutionStr.map { it.digitToInt() }.chunked(9)
}

