    val PUZZLES_BY_DIFFICULTY: Map<String, List<PregeneratedSudoku>> by lazy { ALL_PUZZLES.groupBy { it.difficulty } }

    fun getPuzzleById(id: String): PregeneratedSudoku? = ALL_PUZZLES.find { it.id == id }

    fun getRandomPuzzle(difficulty: String): PregeneratedSudoku? {
        return PUZZLES_BY_DIFFICULTY[difficulty]?.randomOrNull()
    }
